function SettingsPage({ token, showToast }) {
  const [slack, setSlack] = useState("");
  const [teams, setTeams] = useState("");
  const [siem, setSiem] = useState("");
  const [testingSiem, setTestingSiem] = useState(false);
  const [notifyCritical, setNotifyCritical] = useState(true);
  const [notifyHigh, setNotifyHigh] = useState(true);
  const [notifyCve, setNotifyCve] = useState(false);
  const [saving, setSaving] = useState(false);
  const [testingSlack, setTestingSlack] = useState(false);
  const [testingTeams, setTestingTeams] = useState(false);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    axios.get("http://localhost:5001/api/settings", {
      headers: { Authorization: `Bearer ${token}` }
    }).then(r => {
      setSlack(r.data.slack_webhook_url || "");
      setTeams(r.data.teams_webhook_url || "");
      setSiem(r.data.siem_webhook_url || "");
      setNotifyCritical(r.data.notify_critical);
      setNotifyHigh(r.data.notify_high);
      setNotifyCve(r.data.notify_cve);
    }).catch(() => {});
  }, [token]);

  const save = async () => {
    setSaving(true);
    try {
      await axios.put("http://localhost:5001/api/settings", {
        slack_webhook_url: slack, teams_webhook_url: teams, siem_webhook_url: siem,
        notify_critical: notifyCritical, notify_high: notifyHigh, notify_cve: notifyCve
      }, { headers: { Authorization: `Bearer ${token}` } });
      setSaved(true);
      setTimeout(() => setSaved(false), 3000);
      showToast("Settings saved successfully", "success");
    } catch { showToast("Failed to save settings", "error"); }
    setSaving(false);
  };

  const testSlack = async () => {
    if (!slack) { showToast("Enter a Slack webhook URL first", "error"); return; }
    setTestingSlack(true);
    try {
      await axios.post("http://localhost:5001/api/settings/test-slack",
        { slack_webhook_url: slack }, { headers: { Authorization: `Bearer ${token}` } });
      showToast("Test message sent to Slack!", "success");
    } catch { showToast("Slack test failed - check your webhook URL", "error"); }
    setTestingSlack(false);
  };

  const testTeams = async () => {
    if (!teams) { showToast("Enter a Teams webhook URL first", "error"); return; }
    setTestingTeams(true);
    try {
      await axios.post("http://localhost:5001/api/settings/test-teams",
        { teams_webhook_url: teams }, { headers: { Authorization: `Bearer ${token}` } });
      showToast("Test message sent to Teams!", "success");
    } catch { showToast("Teams test failed - check your webhook URL", "error"); }
    setTestingTeams(false);
  };

  const C = { card: "#0f1729", border: "#1e3a5f", blue: "#00b4d8", text: "#e2e8f0", muted: "#64748b", green: "#10b981" };

  const Toggle = ({ value, onChange }) => (
    <div onClick={() => onChange(!value)} style={{ width: "44px", height: "24px", borderRadius: "12px", background: value ? C.blue : "#1e3a5f", cursor: "pointer", position: "relative", transition: "background 0.2s", flexShrink: 0 }}>
      <div style={{ position: "absolute", top: "3px", left: value ? "23px" : "3px", width: "18px", height: "18px", borderRadius: "50%", background: "#fff", transition: "left 0.2s" }} />
    </div>
  );

  const StatusBadge = ({ connected }) => (
    <span style={{ display: "inline-flex", alignItems: "center", gap: "5px", padding: "3px 10px", borderRadius: "100px", fontSize: "11px", fontWeight: "600", background: connected ? "#10b98120" : "#64748b20", color: connected ? C.green : C.muted, border: `1px solid ${connected ? "#10b98140" : "#64748b40"}` }}>
      <span style={{ width: "6px", height: "6px", borderRadius: "50%", background: connected ? C.green : C.muted, display: "inline-block" }} />
      {connected ? "Connected" : "Not configured"}
    </span>
  );

  const WebhookCard = ({ icon, title, color, value, onChange, placeholder, onTest, testing }) => (
    <div style={{ background: C.card, border: `1px solid ${value ? C.blue + "60" : C.border}`, borderRadius: "16px", padding: "24px", marginBottom: "16px", transition: "border 0.2s" }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "16px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <div style={{ width: "36px", height: "36px", borderRadius: "8px", background: color + "20", border: `1px solid ${color}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px" }}>{icon}</div>
          <span style={{ color: C.text, fontWeight: "700", fontSize: "16px" }}>{title}</span>
        </div>
        <StatusBadge connected={!!value} />
      </div>
      <input
        style={{ width: "100%", padding: "11px 14px", borderRadius: "8px", background: "#060d1a", border: `1px solid ${value ? C.blue + "60" : C.border}`, color: C.text, fontSize: "13px", outline: "none", boxSizing: "border-box", transition: "border 0.2s", fontFamily: "JetBrains Mono, monospace" }}
        placeholder={placeholder} value={value} onChange={e => onChange(e.target.value)}
      />
      <div style={{ marginTop: "12px", display: "flex", alignItems: "center", gap: "10px" }}>
        <button onClick={onTest} disabled={testing}
          style={{ padding: "8px 18px", borderRadius: "8px", border: `1px solid ${color}60`, background: color + "15", color: color, fontWeight: "600", fontSize: "13px", cursor: "pointer", opacity: testing ? 0.6 : 1, transition: "all 0.2s" }}>
          {testing ? "Sending..." : "Send Test Message"}
        </button>
        <span style={{ fontSize: "12px", color: C.muted }}>Verify your webhook is working</span>
      </div>
    </div>
  );

  return (
    <div style={{ padding: "32px 40px", maxWidth: "900px" }}>

      {/* Header */}
      <div style={{ marginBottom: "40px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "12px", marginBottom: "8px" }}>
          <div style={{ width: "40px", height: "40px", borderRadius: "12px", background: `${C.blue}20`, border: `1px solid ${C.blue}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>🔔</div>
          <h2 style={{ color: C.text, fontSize: "26px", fontWeight: "800", margin: 0, letterSpacing: "-0.02em" }}>Alert Settings</h2>
        </div>
        <p style={{ color: C.muted, fontSize: "14px", margin: 0, paddingLeft: "52px" }}>
          Get real-time security alerts in Slack or Microsoft Teams when critical threats are detected.
        </p>
      </div>

      {/* How to get webhook URL */}
      <div style={{ background: `${C.blue}08`, border: `1px solid ${C.blue}25`, borderRadius: "14px", padding: "16px 20px", marginBottom: "32px", display: "flex", alignItems: "flex-start", gap: "12px" }}>
        <span style={{ fontSize: "18px", flexShrink: 0 }}>💡</span>
        <div>
          <div style={{ color: C.text, fontSize: "13px", fontWeight: "600", marginBottom: "4px" }}>How to get your webhook URL</div>
          <span style={{ color: C.muted, fontSize: "13px" }}>
            Slack: <strong style={{ color: C.blue }}>Apps → Incoming Webhooks → Add New Webhook</strong>
            &nbsp;&nbsp;·&nbsp;&nbsp;
            Teams: <strong style={{ color: C.blue }}>Channel → Connectors → Incoming Webhook</strong>
          </span>
        </div>
      </div>

      {/* Integration cards */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", marginBottom: "24px" }}>
        {/* Slack */}
        <div style={{ background: C.card, border: `1px solid ${slack ? "#4A154B80" : C.border}`, borderRadius: "20px", padding: "28px", transition: "all 0.2s", boxShadow: slack ? "0 0 30px rgba(74,21,75,0.15)" : "none" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "20px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
              <div style={{ width: "40px", height: "40px", borderRadius: "10px", background: "#4A154B20", border: "1px solid #4A154B40", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>💬</div>
              <div>
                <div style={{ color: C.text, fontWeight: "700", fontSize: "15px" }}>Slack</div>
                <div style={{ color: C.muted, fontSize: "11px" }}>Incoming Webhook</div>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px", padding: "4px 10px", borderRadius: "100px", background: slack ? "#00ff8820" : `${C.border}30`, border: `1px solid ${slack ? "#00ff8840" : C.border}` }}>
              <div style={{ width: "6px", height: "6px", borderRadius: "50%", background: slack ? "#00ff88" : C.muted, boxShadow: slack ? "0 0 6px #00ff88" : "none" }} />
              <span style={{ fontSize: "11px", fontWeight: "600", color: slack ? "#00ff88" : C.muted }}>{slack ? "Configured" : "Not configured"}</span>
            </div>
          </div>
          <input
            style={{ width: "100%", padding: "12px 14px", borderRadius: "10px", background: "#060d1a", border: `1px solid ${slack ? "#4A154B60" : C.border}`, color: C.text, fontSize: "12px", outline: "none", boxSizing: "border-box", fontFamily: "JetBrains Mono, monospace" }}
            placeholder="https://hooks.slack.com/services/T.../B.../..." value={slack} onChange={e => setSlack(e.target.value)}
          />
          <button onClick={testSlack} disabled={testingSlack || !slack}
            style={{ marginTop: "14px", width: "100%", padding: "10px", borderRadius: "8px", border: "1px solid #4A154B60", background: "#4A154B20", color: "#c46ec4", fontWeight: "600", fontSize: "13px", cursor: slack ? "pointer" : "not-allowed", opacity: !slack ? 0.5 : 1, transition: "all 0.2s" }}>
            {testingSlack ? "Sending..." : "🚀 Send Test Message"}
          </button>
        </div>

        {/* Teams */}
        <div style={{ background: C.card, border: `1px solid ${teams ? "#464EB880" : C.border}`, borderRadius: "20px", padding: "28px", transition: "all 0.2s", boxShadow: teams ? "0 0 30px rgba(70,78,184,0.15)" : "none" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "20px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
              <div style={{ width: "40px", height: "40px", borderRadius: "10px", background: "#464EB820", border: "1px solid #464EB840", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>🟦</div>
              <div>
                <div style={{ color: C.text, fontWeight: "700", fontSize: "15px" }}>Microsoft Teams</div>
                <div style={{ color: C.muted, fontSize: "11px" }}>Incoming Webhook</div>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px", padding: "4px 10px", borderRadius: "100px", background: teams ? "#00ff8820" : `${C.border}30`, border: `1px solid ${teams ? "#00ff8840" : C.border}` }}>
              <div style={{ width: "6px", height: "6px", borderRadius: "50%", background: teams ? "#00ff88" : C.muted, boxShadow: teams ? "0 0 6px #00ff88" : "none" }} />
              <span style={{ fontSize: "11px", fontWeight: "600", color: teams ? "#00ff88" : C.muted }}>{teams ? "Configured" : "Not configured"}</span>
            </div>
          </div>
          <input
            style={{ width: "100%", padding: "12px 14px", borderRadius: "10px", background: "#060d1a", border: `1px solid ${teams ? "#464EB860" : C.border}`, color: C.text, fontSize: "12px", outline: "none", boxSizing: "border-box", fontFamily: "JetBrains Mono, monospace" }}
            placeholder="https://outlook.office.com/webhook/..." value={teams} onChange={e => setTeams(e.target.value)}
          />
          <button onClick={testTeams} disabled={testingTeams || !teams}
            style={{ marginTop: "14px", width: "100%", padding: "10px", borderRadius: "8px", border: "1px solid #464EB860", background: "#464EB820", color: "#8b93f0", fontWeight: "600", fontSize: "13px", cursor: teams ? "pointer" : "not-allowed", opacity: !teams ? 0.5 : 1, transition: "all 0.2s" }}>
            {testingTeams ? "Sending..." : "🚀 Send Test Message"}
          </button>
        </div>
      </div>

      {/* SIEM Webhook */}
      <div style={{ background: C.card, border: `1px solid ${siem ? "#e11d4880" : C.border}`, borderRadius: "20px", padding: "28px", marginBottom: "20px", transition: "all 0.2s" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "20px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
            <div style={{ width: "40px", height: "40px", borderRadius: "10px", background: "#e11d4820", border: "1px solid #e11d4840", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "20px" }}>🔌</div>
            <div>
              <div style={{ color: C.text, fontWeight: "700", fontSize: "15px" }}>SIEM Webhook</div>
              <div style={{ color: C.muted, fontSize: "11px" }}>Splunk HEC · IBM QRadar · Microsoft Sentinel</div>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "6px", padding: "4px 10px", borderRadius: "100px", background: siem ? "#00ff8820" : `${C.border}30`, border: `1px solid ${siem ? "#00ff8840" : C.border}` }}>
            <div style={{ width: "6px", height: "6px", borderRadius: "50%", background: siem ? "#00ff88" : C.muted }} />
            <span style={{ fontSize: "11px", fontWeight: "600", color: siem ? "#00ff88" : C.muted }}>{siem ? "Configured" : "Not configured"}</span>
          </div>
        </div>
        <input
          style={{ width: "100%", padding: "12px 14px", borderRadius: "10px", background: "#060d1a", border: `1px solid ${siem ? "#e11d4860" : C.border}`, color: C.text, fontSize: "12px", outline: "none", boxSizing: "border-box", fontFamily: "JetBrains Mono, monospace" }}
          placeholder="https://your-splunk:8088/services/collector or https://qradar/api/..." value={siem} onChange={e => setSiem(e.target.value)}
        />
        <button onClick={async () => {
          setTestingSiem(true);
          try {
            const r = await fetch("http://localhost:5001/api/settings/test-siem", { method: "POST", headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` }, body: JSON.stringify({ siem_webhook_url: siem }) });
            const d = await r.json();
            if (d.success) showToast("SIEM test event sent!", "success");
            else showToast(d.error || "Failed", "error");
          } catch { showToast("Connection failed", "error"); }
          setTestingSiem(false);
        }} disabled={testingSiem || !siem}
          style={{ marginTop: "14px", width: "100%", padding: "10px", borderRadius: "8px", border: "1px solid #e11d4860", background: "#e11d4820", color: "#f43f5e", fontWeight: "600", fontSize: "13px", cursor: siem ? "pointer" : "not-allowed", opacity: !siem ? 0.5 : 1 }}>
          {testingSiem ? "Sending..." : "🚀 Send Test Event"}
        </button>
      </div>

      {/* Notification preferences */}
      <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: "20px", padding: "28px", marginBottom: "28px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "24px" }}>
          <div style={{ width: "36px", height: "36px", borderRadius: "10px", background: `${C.blue}15`, border: `1px solid ${C.blue}30`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px" }}>⚙️</div>
          <div>
            <div style={{ color: C.text, fontWeight: "700", fontSize: "15px" }}>Notification Preferences</div>
            <div style={{ color: C.muted, fontSize: "12px" }}>Choose which events trigger alerts</div>
          </div>
        </div>
        {[
          { label: "Critical severity findings", desc: "Immediate alert for CRITICAL vulnerabilities", value: notifyCritical, set: setNotifyCritical, color: "#ff4444" },
          { label: "High severity findings", desc: "Alert for HIGH severity vulnerabilities", value: notifyHigh, set: setNotifyHigh, color: "#f59e0b" },
          { label: "New CVEs match my devices", desc: "Alert when new CVEs affect your device inventory", value: notifyCve, set: setNotifyCve, color: C.blue },
        ].map(({ label, desc, value, set, color }) => (
          <div key={label} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px", marginBottom: "8px", borderRadius: "12px", background: value ? `${color}08` : "transparent", border: `1px solid ${value ? color + "20" : "transparent"}`, transition: "all 0.2s" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <div style={{ width: "8px", height: "8px", borderRadius: "50%", background: value ? color : C.muted, boxShadow: value ? `0 0 8px ${color}` : "none", flexShrink: 0 }} />
              <div>
                <div style={{ color: C.text, fontSize: "14px", fontWeight: "600", marginBottom: "2px" }}>{label}</div>
                <div style={{ color: C.muted, fontSize: "12px" }}>{desc}</div>
              </div>
            </div>
            <Toggle value={value} onChange={set} />
          </div>
        ))}
      </div>

      {/* Save button */}
      <button onClick={save} disabled={saving}
        style={{ width: "100%", padding: "16px", borderRadius: "12px", border: "none", background: saved ? "#00ff88" : `linear-gradient(135deg, ${C.blue}, #0099cc)`, color: saved ? "#000" : "#fff", fontWeight: "700", fontSize: "16px", cursor: "pointer", opacity: saving ? 0.7 : 1, transition: "all 0.3s", boxShadow: saved ? "0 0 30px #00ff8840" : `0 0 30px ${C.blue}30`, letterSpacing: "-0.01em" }}>
        {saving ? "Saving..." : saved ? "✓ Settings Saved!" : "Save Settings"}
      </button>

    </div>
  );
}


// ─────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────
// AIPET X — Terminal v2.0
//
// Features:
//   • REST-based command execution (no SocketIO)
//   • Command history (↑/↓ navigation)
//   • Built-in: help, clear, banner, + backend commands
//   • AIPET X dark theme (cyan / near-black / JetBrains Mono)
// ─────────────────────────────────────────────────────────────
function AIPETTerminal({ token, showToast }) {
  const [output,     setOutput]     = useState([
    { type:"system", text:"  AIPET X  -  Terminal v2.0",                  color:"#00e5ff" },
    { type:"system", text:"  AI-Powered IoT Security Suite",               color:"#64748b" },
    { type:"system", text:"",                                              color:"#64748b" },
    { type:"system", text:"  Zero-Trust verified  |  25 modules connected",color:"#00ff88" },
    { type:"system", text:"",                                              color:"#64748b" },
    { type:"system", text:"  Type help for commands",                      color:"#334155" },
    { type:"system", text:"",                                              color:"#64748b" },
  ]);
  const [input,      setInput]      = useState("");
  const [cmdHistory, setCmdHistory] = useState([]);
  const [histIdx,    setHistIdx]    = useState(-1);
  const [busy,       setBusy]       = useState(false);
  const [nlPending,  setNlPending]  = useState(null);
  const bottomRef = useRef(null);
  const inputRef  = useRef(null);

  const AUTH = { headers: { Authorization: "Bearer " + token } };
  const CYAN="#00e5ff",GREEN="#00ff88",RED="#ff3b5c",ORANGE="#ff8c00",
        PURPLE="#a78bfa",MUTED="#64748b",TEXT="#e2e8f0",
        BG="#030712",CARD="#0a0f1a",BORDER="#1e2a3a",FAINT="#1e293b";

  useEffect(() => {
    if (bottomRef.current)
      bottomRef.current.scrollIntoView({ behavior:"smooth" });
  }, [output]);

  const addLines = (lines) => {
    if (!Array.isArray(lines)) return;
    setOutput(prev => [
      ...prev,
      ...lines
        .filter(l => l !== null && l !== undefined)
        .map(l => ({ type:"output", text:String(l), color:TEXT }))
    ]);
  };

  const addSystem = (text, color) =>
    setOutput(prev => [...prev,
      { type:"system", text:String(text||""), color:color||CYAN }]);

  const addError = (text) =>
    setOutput(prev => [...prev,
      { type:"error", text:String(text||"Error"), color:RED }]);

  const runCommand = async (cmd) => {
    if (!cmd || !cmd.trim()) return;
    const trimmed = cmd.trim();
    setOutput(prev => [...prev, { type:"input", text:trimmed, color:CYAN }]);
    setCmdHistory(prev => [trimmed, ...prev.filter(h=>h!==trimmed)].slice(0,50));
    setHistIdx(-1);
    setInput("");
    setNlPending(null);
    setBusy(true);
    try {
      const res  = await axios.post(API+"/terminal/command",{command:trimmed},AUTH);
      const data = res.data;
      if (!data) { addError("No response"); return; }
      if (data.render==="clear") { setOutput([]); return; }
      if (data.render==="nl_detect") {
        setNlPending(trimmed);
        addSystem("Natural language detected — press Enter to translate or Escape to cancel","#ffd600");
        return;
      }
      if (Array.isArray(data.lines)) addLines(data.lines);
      else if (data.error) addError(data.error);
    } catch(err) {
      addError("Request failed: "+(err.message||"unknown"));
    } finally {
      setBusy(false);
      if (inputRef.current) inputRef.current.focus();
    }
  };

  const runNL = async () => {
    if (!nlPending) return;
    const text = nlPending;
    setNlPending(null);
    addSystem("[AI] Translating...",PURPLE);
    setBusy(true);
    try {
      const res  = await axios.post(API+"/terminal/nl",{text},AUTH);
      const data = res.data;
      if (!data) { addError("No response"); return; }
      if (data.nl_translated) addSystem("[AI] Executing: "+data.nl_translated,PURPLE);
      if (Array.isArray(data.lines)) addLines(data.lines);
    } catch(err) {
      addError("AI error: "+(err.message||"unknown"));
    } finally {
      setBusy(false);
      if (inputRef.current) inputRef.current.focus();
    }
  };

  const handleKey = (e) => {
    if (e.key==="Enter") {
      e.preventDefault();
      if (nlPending) { runNL(); return; }
      if (input.trim()) runCommand(input.trim());
      return;
    }
    if (e.key==="Escape") { setNlPending(null); return; }
    if (e.key==="ArrowUp") {
      e.preventDefault();
      const idx=Math.min(histIdx+1,cmdHistory.length-1);
      setHistIdx(idx); setInput(cmdHistory[idx]||"");
      return;
    }
    if (e.key==="ArrowDown") {
      e.preventDefault();
      const idx=Math.max(histIdx-1,-1);
      setHistIdx(idx); setInput(idx===-1?"":(cmdHistory[idx]||""));
      return;
    }
  };

  const getColor = (line) => {
    if (!line) return TEXT;
    if (line.color) return line.color;
    if (line.type==="error") return RED;
    if (line.type==="system") return CYAN;
    if (line.type==="input") return CYAN;
    const t = String(line.text||"");
    if (t.includes("CRITICAL")||t.includes("[Critical]")) return RED;
    if (t.includes("[High]")||t.includes("HIGH"))         return ORANGE;
    if (t.startsWith("  \u2713")||t.includes("HEALTHY"))  return GREEN;
    if (t.startsWith("  \u2717")||t.includes("FAILED"))   return RED;
    if (t.includes("[AI]"))                               return PURPLE;
    return TEXT;
  };

  const SHORTCUTS=["help","status","identity risks","compliance status",
    "supply vulns","behavioral anomalies","cost recs","network issues"];

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100vh",
      background:BG,fontFamily:"JetBrains Mono, monospace"}}
      onClick={()=>inputRef.current&&inputRef.current.focus()}>

      {/* Title bar */}
      <div style={{display:"flex",alignItems:"center",
        justifyContent:"space-between",padding:"8px 20px",
        background:CARD,borderBottom:"1px solid "+BORDER,flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",gap:"10px"}}>
          <div style={{display:"flex",gap:"5px"}}>
            {["#ff3b5c","#ffd600","#00ff88"].map((c,i)=>(
              <div key={i} style={{width:"11px",height:"11px",
                borderRadius:"50%",background:c}}/>
            ))}
          </div>
          <span style={{fontSize:"11px",color:MUTED}}>
            aipet-shell — secure@aipet-x
          </span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:"12px"}}>
          {busy&&<span style={{fontSize:"10px",color:CYAN}}>● Processing...</span>}
          <span style={{fontSize:"10px",color:MUTED}}>
            {output.filter(o=>o&&o.type==="input").length} commands
          </span>
        </div>
      </div>

      {/* Output */}
      <div style={{flex:1,overflowY:"auto",padding:"12px 20px"}}>
        {output.map((line,idx)=>{
          if (!line) return null;
          if (line.type==="input") return (
            <div key={idx} style={{display:"flex",gap:"8px",marginTop:"6px"}}>
              <span style={{color:CYAN,fontWeight:"700",
                fontSize:"12px",flexShrink:0}}>aipet&gt;</span>
              <span style={{color:TEXT,fontSize:"12px"}}>
                {String(line.text||"")}
              </span>
            </div>
          );
          return (
            <div key={idx} style={{fontFamily:"JetBrains Mono, monospace",
              fontSize:"12px",lineHeight:"1.6",color:getColor(line),
              whiteSpace:"pre-wrap",wordBreak:"break-word",minHeight:"4px"}}>
              {String(line.text||"")}
            </div>
          );
        })}
        {busy&&(
          <div style={{display:"flex",gap:"3px",padding:"4px 0"}}>
            {[0,1,2].map(i=>(
              <div key={i} style={{width:"4px",height:"4px",
                borderRadius:"50%",background:CYAN,opacity:0.6}}/>
            ))}
          </div>
        )}
        <div ref={bottomRef}/>
      </div>

      {/* NL banner */}
      {nlPending&&(
        <div style={{padding:"8px 20px",background:"#ffd60010",
          borderTop:"1px solid #ffd60030",display:"flex",
          gap:"10px",alignItems:"center",flexShrink:0}}>
          <span style={{fontSize:"11px",color:"#ffd600"}}>
            AI: "{nlPending}"
          </span>
          <button onClick={runNL}
            style={{padding:"3px 12px",borderRadius:"6px",
              border:"none",background:CYAN,color:"#000",
              cursor:"pointer",fontSize:"11px",fontWeight:"700"}}>
            Enter Execute
          </button>
          <button onClick={()=>setNlPending(null)}
            style={{padding:"3px 12px",borderRadius:"6px",
              border:"1px solid "+BORDER,background:"transparent",
              color:MUTED,cursor:"pointer",fontSize:"11px"}}>
            X Cancel
          </button>
        </div>
      )}

      {/* Quick commands */}
      <div style={{display:"flex",gap:"5px",padding:"5px 20px",
        background:CARD,borderTop:"1px solid "+BORDER,
        flexWrap:"wrap",flexShrink:0}}>
        {SHORTCUTS.map(cmd=>(
          <button key={cmd} onClick={()=>runCommand(cmd)}
            style={{padding:"2px 8px",borderRadius:"5px",
              border:"1px solid "+BORDER,background:"transparent",
              color:MUTED,cursor:"pointer",fontSize:"10px"}}>
            {cmd}
          </button>
        ))}
      </div>

      {/* Input bar */}
      <div style={{display:"flex",alignItems:"center",
        padding:"10px 20px",background:CARD,
        borderTop:"1px solid "+BORDER,gap:"8px",flexShrink:0}}>
        <span style={{color:nlPending?"#ffd600":CYAN,
          fontWeight:"700",fontSize:"13px",flexShrink:0}}>
          {nlPending?"ai>":"aipet>"}
        </span>
        <input ref={inputRef}
          value={input}
          onChange={e=>setInput(e.target.value)}
          onKeyDown={handleKey}
          disabled={busy}
          placeholder="Enter command or ask a question..."
          autoFocus
          style={{flex:1,background:"transparent",border:"none",
            outline:"none",color:TEXT,fontSize:"13px",
            fontFamily:"JetBrains Mono, monospace",caretColor:CYAN}}/>
        {input&&(
          <button onClick={()=>runCommand(input.trim())}
            style={{padding:"4px 12px",borderRadius:"6px",
              border:"none",background:CYAN,color:"#000",
              cursor:"pointer",fontSize:"12px",
              fontWeight:"700",flexShrink:0}}>
            Run
          </button>
        )}
      </div>

      {/* Hint */}
      <div style={{padding:"3px 20px 6px",background:CARD,
        fontSize:"10px",color:FAINT}}>
        up/down history · Enter execute · Escape cancel
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────
// AIPET X — Unified Security Timeline Enhanced Page
//
// Features:
//   • Collects events from ALL 11 Phase 5B modules
//   • AI correlation clusters — groups related events
//   • Cross-module attack chain visualization
//   • Claude AI summary per cluster
//   • Filter by module, severity, correlated
//   • Stats: events, clusters, modules covered
//   • Resolve events
// ─────────────────────────────────────────────────────────────
function TimelineEnhancedPage({ token, showToast }) {

  const [events,    setEvents]    = useState([]);
  const [clusters,  setClusters]  = useState([]);
  const [stats,     setStats]     = useState(null);
  const [loading,   setLoading]   = useState(true);
  const [collecting,setCollecting]= useState(false);
  const [correlating,setCorrelating]=useState(false);
  const [tab,       setTab]       = useState("clusters");
  const [sevFilter, setSevFilter] = useState("");
  const [modFilter, setModFilter] = useState("");
  const [updating,  setUpdating]  = useState({});
  const [expanded,  setExpanded]  = useState({});

  const H = { headers: { Authorization: `Bearer ${token}` } };

  const MODULE_META = {
    behavioral:     { color:"#a78bfa", icon:"🧠", label:"Behavioral AI"   },
    identity_graph: { color:"#00e5ff", icon:"🕸️", label:"Identity Graph"  },
    drift:          { color:"#ff8c00", icon:"🎯", label:"Drift Detector"  },
    dspm:           { color:"#00e5ff", icon:"🛡️", label:"Data Security"  },
    api_security:   { color:"#ff8c00", icon:"🔌", label:"API Security"    },
    supply_chain:   { color:"#a78bfa", icon:"🔗", label:"Supply Chain"    },
    network:        { color:"#00ff88", icon:"🗺️", label:"Network"         },
    compliance:     { color:"#00ff88", icon:"📋", label:"Compliance"      },
    cost_security:  { color:"#00ff88", icon:"💰", label:"Cost Security"   },
    resilience:     { color:"#00ff88", icon:"🛡️", label:"Resilience"     },
    siem:           { color:"#ff3b5c", icon:"⚡", label:"SIEM"            },
    scan:           { color:"#00e5ff", icon:"🔍", label:"Scan"            },
    user:           { color:"#64748b", icon:"👤", label:"User"            },
  };

  const SEV_COLOR = {
    Critical:"#ff3b5c", High:"#ff8c00",
    Medium:"#ffd600",   Low:"#00ff88", Info:"#64748b",
  };

  const CLUSTER_TYPE_META = {
    attack_chain:      { icon:"⚔️",  color:"#ff3b5c", label:"Attack Chain"      },
    policy_violation:  { icon:"📋",  color:"#ff8c00", label:"Policy Violation"  },
    anomaly_group:     { icon:"⚡",  color:"#ffd600", label:"Anomaly Group"     },
    compliance_breach: { icon:"⚠️",  color:"#ff8c00", label:"Compliance Breach" },
    data_incident:     { icon:"🗄️", color:"#ff3b5c", label:"Data Incident"     },
  };

  const C = {
    bg:"#030712", card:"#0d1117", surface:"#080f1a",
    border:"#1e2a3a", text:"#e2e8f0", muted:"#64748b",
    faint:"#334155", cyan:"#00e5ff",
  };
  const cardStyle = (extra={}) => ({
    background:C.card, border:`1px solid ${C.border}`,
    borderRadius:"16px", padding:"24px", ...extra
  });

  const fetchAll = useCallback(async () => {
    try {
      const params = new URLSearchParams({ days:7, per_page:50 });
      if (sevFilter) params.append("severity", sevFilter);
      if (modFilter) params.append("source_module", modFilter);
      const [evRes, clRes, stRes] = await Promise.all([
        axios.get(`${API}/timeline_enhanced/events?${params}`, H),
        axios.get(`${API}/timeline_enhanced/clusters`, H),
        axios.get(`${API}/timeline_enhanced/stats`, H),
      ]);
      setEvents(evRes.data.events   || []);
      setClusters(clRes.data.clusters || []);
      setStats(stRes.data);
    } catch { showToast("Failed to load timeline", "error"); }
    finally { setLoading(false); }
  }, [token, sevFilter, modFilter]);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const handleCollect = async () => {
    setCollecting(true);
    try {
      const res = await axios.post(`${API}/timeline_enhanced/collect`, {}, H);
      showToast(`Collected ${res.data.events_added} new events from all modules`, "success");
      fetchAll();
    } catch { showToast("Collection failed", "error"); }
    finally { setCollecting(false); }
  };

  const handleCorrelate = async () => {
    setCorrelating(true);
    try {
      const res = await axios.post(`${API}/timeline_enhanced/correlate`, {}, H);
      showToast(`AI correlation: ${res.data.clusters_created} new clusters created`, "success");
      fetchAll();
    } catch { showToast("Correlation failed", "error"); }
    finally { setCorrelating(false); }
  };

  const handleResolve = async (eid) => {
    setUpdating(prev => ({ ...prev, [eid]: true }));
    try {
      await axios.put(`${API}/timeline_enhanced/events/${eid}`,
        { resolved: true }, H);
      fetchAll();
      showToast("Resolved", "success");
    } catch { showToast("Failed", "error"); }
    finally { setUpdating(prev => ({ ...prev, [eid]: false })); }
  };

  const formatTime = (dt) => {
    const d    = new Date(dt);
    const diff = Math.floor((new Date() - d) / 1000);
    if (diff < 3600)  return `${Math.floor(diff/60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff/3600)}h ago`;
    return `${Math.floor(diff/86400)}d ago`;
  };

  if (loading) return (
    <div style={{ display:"flex", justifyContent:"center",
      alignItems:"center", height:"60vh" }}>
      <div style={{ width:"48px", height:"48px",
        border:`3px solid ${C.border}`,
        borderTop:`3px solid ${C.cyan}`,
        borderRadius:"50%", animation:"spin 1s linear infinite" }} />
    </div>
  );

  return (
    <div style={{ padding:"32px 36px", background:C.bg,
      minHeight:"100vh", fontFamily:"Inter, sans-serif", color:C.text }}>

      {/* Header */}
      <div style={{ display:"flex", alignItems:"center",
        justifyContent:"space-between", marginBottom:"32px" }}>
        <div style={{ display:"flex", alignItems:"center", gap:"16px" }}>
          <div style={{ width:"52px", height:"52px", borderRadius:"14px",
            background:"linear-gradient(135deg, #00e5ff20, #a78bfa08)",
            border:"1px solid #00e5ff35", display:"flex",
            alignItems:"center", justifyContent:"center", fontSize:"24px",
            boxShadow:"0 0 20px #00e5ff15" }}>📅</div>
          <div>
            <h1 style={{ margin:0, fontSize:"26px", fontWeight:"800",
              letterSpacing:"-0.5px", fontFamily:"JetBrains Mono, monospace",
              background:"linear-gradient(135deg, #00e5ff, #a78bfa)",
              WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent" }}>
              Unified Security Timeline
            </h1>
            <div style={{ fontSize:"13px", color:C.muted, marginTop:"2px" }}>
              All modules · AI correlation · Cross-module attack chains · Claude AI summaries
            </div>
          </div>
        </div>
        <div style={{ display:"flex", gap:"10px" }}>
          <button onClick={handleCollect} disabled={collecting}
            style={{ padding:"10px 20px", borderRadius:"10px",
              border:"1px solid #00e5ff35", cursor:"pointer",
              fontSize:"13px", fontWeight:"700",
              background:collecting ? C.surface : "#00e5ff15",
              color:collecting ? C.muted : "#00e5ff" }}>
            {collecting ? "Collecting..." : "↓ Collect Events"}
          </button>
          <button onClick={handleCorrelate} disabled={correlating}
            style={{ padding:"10px 20px", borderRadius:"10px",
              border:"none", cursor:"pointer",
              fontSize:"13px", fontWeight:"800",
              background:correlating ? C.surface
                : "linear-gradient(135deg, #00e5ff, #a78bfa)",
              color:correlating ? C.muted : "#000",
              boxShadow:correlating ? "none"
                : "0 0 20px rgba(0,229,255,0.3)" }}>
            {correlating ? "Correlating..." : "🤖 AI Correlate"}
          </button>
        </div>
      </div>

      {/* Stats */}
      {stats && (
        <div style={{ display:"grid", gridTemplateColumns:"repeat(6,1fr)",
          gap:"12px", marginBottom:"28px" }}>
          {[
            { label:"Events",      value:stats.total_events,     color:"#00e5ff", icon:"📅" },
            { label:"Clusters",    value:stats.total_clusters,   color:"#a78bfa", icon:"🔗" },
            { label:"Critical",    value:stats.critical_events,  color:"#ff3b5c", icon:"🚨" },
            { label:"Correlated",  value:stats.correlated_events,color:"#ffd600", icon:"⚡" },
            { label:"Unresolved",  value:stats.unresolved,       color:"#ff8c00", icon:"⏳" },
            { label:"Modules",     value:stats.modules_covered,  color:"#00ff88", icon:"📡" },
          ].map(s => (
            <div key={s.label} style={{ ...cardStyle({ padding:"18px" }),
              borderColor:s.color+"25" }}>
              <div style={{ fontSize:"18px", marginBottom:"6px" }}>{s.icon}</div>
              <div style={{ fontSize:"22px", fontWeight:"800",
                fontFamily:"JetBrains Mono, monospace",
                color:s.color, lineHeight:1 }}>{s.value}</div>
              <div style={{ fontSize:"10px", color:C.muted, marginTop:"4px",
                textTransform:"uppercase", letterSpacing:"0.5px" }}>{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Tabs */}
      <div style={{ display:"flex", gap:"4px", marginBottom:"20px",
        background:C.card, padding:"4px", borderRadius:"12px",
        border:`1px solid ${C.border}`, width:"fit-content" }}>
        {[
          { id:"clusters", label:`Clusters (${clusters.length})`  },
          { id:"events",   label:`All Events (${events.length})`  },
        ].map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            style={{ padding:"8px 18px", borderRadius:"9px", border:"none",
              cursor:"pointer", fontSize:"13px", fontWeight:"600",
              transition:"all 0.2s",
              background:tab===t.id
                ?"linear-gradient(135deg,#00e5ff20,#a78bfa08)":"transparent",
              color:tab===t.id?C.text:C.muted,
              boxShadow:tab===t.id?"inset 0 0 0 1px #00e5ff30":"none" }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Clusters tab */}
      {tab === "clusters" && (
        <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
          {clusters.length === 0 ? (
            <div style={{ ...cardStyle({ padding:"48px", textAlign:"center" }),
              color:C.muted }}>
              <div style={{ fontSize:"32px", marginBottom:"12px" }}>🤖</div>
              <div style={{ fontSize:"14px", color:C.text, marginBottom:"8px" }}>
                No correlated clusters yet
              </div>
              <div style={{ fontSize:"12px" }}>
                Click "Collect Events" then "AI Correlate" to detect attack chains
              </div>
            </div>
          ) : clusters.map(cluster => {
            const ct  = CLUSTER_TYPE_META[cluster.cluster_type] ||
              { icon:"⚡", color:"#64748b", label:cluster.cluster_type };
            const sc  = SEV_COLOR[cluster.severity] || "#64748b";
            const isExp = expanded[cluster.id];
            return (
              <div key={cluster.id} style={{ ...cardStyle({
                borderColor:sc+"30",
                borderLeft:`4px solid ${sc}` }) }}>
                {/* Cluster header */}
                <div style={{ display:"flex", alignItems:"flex-start",
                  gap:"14px", cursor:"pointer" }}
                  onClick={() => setExpanded(prev =>
                    ({ ...prev, [cluster.id]: !isExp }))}>
                  <div style={{ fontSize:"24px", flexShrink:0 }}>
                    {ct.icon}
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", gap:"8px",
                      flexWrap:"wrap", marginBottom:"6px" }}>
                      <span style={{ padding:"2px 8px",
                        borderRadius:"100px", fontSize:"9px",
                        fontWeight:"800", background:sc+"15",
                        color:sc, textTransform:"uppercase" }}>
                        {cluster.severity}
                      </span>
                      <span style={{ padding:"2px 8px",
                        borderRadius:"100px", fontSize:"10px",
                        background:ct.color+"15", color:ct.color }}>
                        {ct.label}
                      </span>
                      <span style={{ fontSize:"10px", color:C.muted }}>
                        {cluster.event_count} events
                      </span>
                      {cluster.modules_involved?.map(m => {
                        const mm = MODULE_META[m] || { color:"#64748b", icon:"📡" };
                        return (
                          <span key={m} style={{ padding:"1px 6px",
                            borderRadius:"100px", fontSize:"9px",
                            background:mm.color+"15", color:mm.color }}>
                            {mm.icon} {m}
                          </span>
                        );
                      })}
                    </div>
                    <div style={{ fontWeight:"700", fontSize:"14px",
                      marginBottom:"8px" }}>{cluster.title}</div>
                    {/* AI Summary */}
                    {cluster.ai_summary && (
                      <div style={{ padding:"10px 14px",
                        borderRadius:"10px",
                        background:"#a78bfa08",
                        border:"1px solid #a78bfa20",
                        marginBottom:"8px" }}>
                        <div style={{ fontSize:"10px", color:"#a78bfa",
                          fontWeight:"700", marginBottom:"4px" }}>
                          🤖 AI Analysis
                        </div>
                        <div style={{ fontSize:"12px", color:C.text,
                          lineHeight:"1.6" }}>
                          {cluster.ai_summary}
                        </div>
                      </div>
                    )}
                  </div>
                  <div style={{ fontSize:"16px", color:C.muted,
                    flexShrink:0 }}>
                    {isExp ? "▲" : "▼"}
                  </div>
                </div>

                {/* Expanded event timeline */}
                {isExp && cluster.events && cluster.events.length > 0 && (
                  <div style={{ marginTop:"16px", paddingTop:"16px",
                    borderTop:`1px solid ${C.border}` }}>
                    <div style={{ fontSize:"10px", fontWeight:"700",
                      color:C.muted, textTransform:"uppercase",
                      letterSpacing:"1.5px", marginBottom:"12px" }}>
                      Attack Timeline
                    </div>
                    <div style={{ position:"relative" }}>
                      {/* Timeline line */}
                      <div style={{ position:"absolute", left:"12px",
                        top:"8px", bottom:"8px", width:"2px",
                        background:C.faint }} />
                      <div style={{ display:"flex",
                        flexDirection:"column", gap:"8px" }}>
                        {cluster.events.map((ev, i) => {
                          const mm = MODULE_META[ev.source_module] ||
                            { color:"#64748b", icon:"📡" };
                          const sc2 = SEV_COLOR[ev.severity] || "#64748b";
                          return (
                            <div key={ev.id} style={{ display:"flex",
                              gap:"12px", paddingLeft:"8px" }}>
                              {/* Timeline dot */}
                              <div style={{ width:"10px", height:"10px",
                                borderRadius:"50%", flexShrink:0,
                                background:sc2, marginTop:"4px",
                                zIndex:1 }} />
                              <div style={{ flex:1, padding:"8px 12px",
                                borderRadius:"8px", background:C.surface,
                                border:`1px solid ${sc2}20` }}>
                                <div style={{ display:"flex",
                                  alignItems:"center", gap:"6px",
                                  marginBottom:"3px" }}>
                                  <span style={{ fontSize:"10px" }}>
                                    {mm.icon}
                                  </span>
                                  <span style={{ fontSize:"10px",
                                    color:mm.color, fontWeight:"600" }}>
                                    {mm.label}
                                  </span>
                                  <span style={{ fontSize:"10px",
                                    color:C.faint, marginLeft:"auto" }}>
                                    {formatTime(ev.created_at)}
                                  </span>
                                </div>
                                <div style={{ fontSize:"12px",
                                  color:C.text, fontWeight:"600" }}>
                                  {ev.title}
                                </div>
                                {ev.entity && (
                                  <div style={{ fontSize:"10px",
                                    color:C.muted, marginTop:"2px",
                                    fontFamily:"JetBrains Mono, monospace" }}>
                                    {ev.entity}
                                  </div>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Events tab */}
      {tab === "events" && (
        <div>
          {/* Filters */}
          <div style={{ display:"flex", gap:"8px",
            flexWrap:"wrap", marginBottom:"16px" }}>
            {["","Critical","High","Medium","Low"].map(s => {
              const color = SEV_COLOR[s] || C.cyan;
              return (
                <button key={s} onClick={() => setSevFilter(s)}
                  style={{ padding:"4px 12px", borderRadius:"100px",
                    border:`1px solid ${sevFilter===s?color:C.border}`,
                    background:sevFilter===s?color+"20":"transparent",
                    color:sevFilter===s?color:C.muted,
                    cursor:"pointer", fontSize:"12px",
                    fontWeight:sevFilter===s?"700":"400" }}>
                  {s||"All"}
                </button>
              );
            })}
            <select value={modFilter}
              onChange={e => setModFilter(e.target.value)}
              style={{ padding:"4px 10px", borderRadius:"10px",
                border:`1px solid ${C.border}`,
                background:C.surface, color:C.text,
                fontSize:"12px", outline:"none", marginLeft:"auto" }}>
              <option value="">All Modules</option>
              {Object.entries(MODULE_META).map(([id,m]) => (
                <option key={id} value={id}>{m.icon} {m.label}</option>
              ))}
            </select>
          </div>

          <div style={{ display:"flex", flexDirection:"column", gap:"6px" }}>
            {events.map(ev => {
              const sc = SEV_COLOR[ev.severity] || "#64748b";
              const mm = MODULE_META[ev.source_module] ||
                { color:"#64748b", icon:"📡", label:ev.source_module };
              return (
                <div key={ev.id} style={{ background:C.card,
                  border:`1px solid ${ev.correlated ? sc+"30" : C.border}`,
                  borderLeft:`3px solid ${sc}`,
                  borderRadius:"10px", padding:"10px 14px",
                  opacity:ev.resolved ? 0.55 : 1 }}>
                  <div style={{ display:"flex",
                    alignItems:"center", gap:"8px" }}>
                    <span style={{ fontSize:"14px" }}>{mm.icon}</span>
                    <span style={{ padding:"2px 7px",
                      borderRadius:"100px", fontSize:"9px",
                      fontWeight:"800", background:sc+"15",
                      color:sc, textTransform:"uppercase",
                      flexShrink:0 }}>{ev.severity}</span>
                    <span style={{ padding:"2px 7px",
                      borderRadius:"100px", fontSize:"10px",
                      background:mm.color+"15", color:mm.color,
                      flexShrink:0 }}>{mm.label}</span>
                    {ev.correlated && (
                      <span style={{ padding:"2px 7px",
                        borderRadius:"100px", fontSize:"9px",
                        background:"#ffd60015", color:"#ffd600",
                        fontWeight:"700", flexShrink:0 }}>
                        🔗 CORRELATED
                      </span>
                    )}
                    {ev.mitre_id && (
                      <span style={{ padding:"2px 7px",
                        borderRadius:"6px", fontSize:"10px",
                        fontWeight:"700", color:"#a78bfa",
                        background:"#7c3aed10",
                        fontFamily:"JetBrains Mono, monospace",
                        flexShrink:0 }}>{ev.mitre_id}</span>
                    )}
                    <span style={{ flex:1, fontSize:"12px",
                      fontWeight:"600", overflow:"hidden",
                      textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                      {ev.title}
                    </span>
                    {ev.entity && (
                      <span style={{ fontSize:"10px", color:C.muted,
                        fontFamily:"JetBrains Mono, monospace",
                        flexShrink:0, whiteSpace:"nowrap" }}>
                        {ev.entity}
                      </span>
                    )}
                    <span style={{ fontSize:"10px", color:C.faint,
                      flexShrink:0 }}>{formatTime(ev.created_at)}</span>
                    {!ev.resolved && (
                      <button onClick={() => handleResolve(ev.id)}
                        disabled={updating[ev.id]}
                        style={{ padding:"3px 8px", borderRadius:"6px",
                          border:"1px solid #00ff8830",
                          cursor:"pointer", fontSize:"10px",
                          background:"#00ff8810", color:"#00ff88",
                          flexShrink:0 }}>✓</button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// AIPET X — Cloud-Identity Drift Detector Page
//
// Features:
//   • Drift score per identity (0-100)
//   • Drift type badges (privilege escalation, wildcard, MFA disabled)
//   • Old vs New permission comparison
//   • Provider filter (AWS/Azure/GCP)
//   • Run scan button
//   • Resolve / Investigate / Accept workflow
//   • Stats: total drifts, critical, avg score
// ─────────────────────────────────────────────────────────────
function DriftDetectorPage({ token, showToast }) {

  const [baselines,  setBaselines]  = useState([]);
  const [drifts,     setDrifts]     = useState([]);
  const [stats,      setStats]      = useState(null);
  const [loading,    setLoading]    = useState(true);
  const [scanning,   setScanning]   = useState(false);
  const [tab,        setTab]        = useState("drifts");
  const [selBaseline,setSelBaseline]= useState(null);
  const [sevFilter,  setSevFilter]  = useState("");
  const [updating,   setUpdating]   = useState({});

  const H = { headers: { Authorization: `Bearer ${token}` } };

  const DRIFT_META = {
    permission_added:     { icon:"➕", label:"Permission Added",     color:"#ff8c00" },
    permission_removed:   { icon:"➖", label:"Permission Removed",   color:"#ffd600" },
    role_added:           { icon:"👤", label:"Role Added",           color:"#ff8c00" },
    role_removed:         { icon:"👤", label:"Role Removed",         color:"#64748b" },
    policy_changed:       { icon:"📝", label:"Policy Changed",       color:"#ffd600" },
    privilege_escalation: { icon:"⬆️", label:"Privilege Escalation", color:"#ff3b5c" },
    dormant_activation:   { icon:"👻", label:"Dormant Activation",   color:"#ff3b5c" },
    cross_account_access: { icon:"🔗", label:"Cross-Account",        color:"#ff3b5c" },
    mfa_disabled:         { icon:"🔓", label:"MFA Disabled",         color:"#ff3b5c" },
    wildcard_permission:  { icon:"⭐", label:"Wildcard Permission",   color:"#ff3b5c" },
  };

  const PROVIDER_COLOR = {
    aws: "#ff8c00", azure: "#00e5ff", gcp: "#00ff88",
    on_premise: "#a78bfa",
  };

  const SEV_COLOR = {
    Critical:"#ff3b5c", High:"#ff8c00",
    Medium:"#ffd600",   Low:"#00ff88",
  };

  const DRIFT_COLOR = (score) =>
    score >= 70 ? "#ff3b5c" :
    score >= 40 ? "#ff8c00" :
    score >= 20 ? "#ffd600" : "#00ff88";

  const C = {
    bg:"#030712", card:"#0d1117", surface:"#080f1a",
    border:"#1e2a3a", text:"#e2e8f0", muted:"#64748b",
    faint:"#334155", cyan:"#00e5ff",
  };
  const cardStyle = (extra={}) => ({
    background:C.card, border:`1px solid ${C.border}`,
    borderRadius:"16px", padding:"24px", ...extra
  });

  const fetchAll = useCallback(async () => {
    try {
      const [bRes, dRes, stRes] = await Promise.all([
        axios.get(`${API}/drift/baselines`, H),
        axios.get(`${API}/drift/drifts?status=open${sevFilter?"&severity="+sevFilter:""}`, H),
        axios.get(`${API}/drift/stats`, H),
      ]);
      setBaselines(bRes.data.baselines || []);
      setDrifts(dRes.data.drifts       || []);
      setStats(stRes.data);
    } catch { showToast("Failed to load drift data", "error"); }
    finally { setLoading(false); }
  }, [token, sevFilter]);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const handleScan = async () => {
    setScanning(true);
    try {
      const res = await axios.post(`${API}/drift/scan`, {}, H);
      showToast(`Scan complete — ${res.data.drifts_found} drifts detected`, "success");
      fetchAll();
    } catch { showToast("Scan failed", "error"); }
    finally { setScanning(false); }
  };

  const handleUpdate = async (did, status) => {
    setUpdating(prev => ({ ...prev, [did]: true }));
    try {
      await axios.put(`${API}/drift/drifts/${did}`, { status }, H);
      fetchAll();
      showToast(`Status → ${status}`, "success");
    } catch { showToast("Failed", "error"); }
    finally { setUpdating(prev => ({ ...prev, [did]: false })); }
  };

  const handleReset = async (bid) => {
    try {
      await axios.post(`${API}/drift/baselines/${bid}/reset`, {}, H);
      fetchAll();
      showToast("Baseline reset — current state accepted as new baseline", "success");
    } catch { showToast("Reset failed", "error"); }
  };

  if (loading) return (
    <div style={{ display:"flex", justifyContent:"center",
      alignItems:"center", height:"60vh" }}>
      <div style={{ width:"48px", height:"48px",
        border:`3px solid ${C.border}`,
        borderTop:`3px solid ${C.cyan}`,
        borderRadius:"50%", animation:"spin 1s linear infinite" }} />
    </div>
  );

  return (
    <div style={{ padding:"32px 36px", background:C.bg,
      minHeight:"100vh", fontFamily:"Inter, sans-serif", color:C.text }}>

      {/* Header */}
      <div style={{ display:"flex", alignItems:"center",
        justifyContent:"space-between", marginBottom:"32px" }}>
        <div style={{ display:"flex", alignItems:"center", gap:"16px" }}>
          <div style={{ width:"52px", height:"52px", borderRadius:"14px",
            background:"linear-gradient(135deg, #ff8c0020, #ffd60008)",
            border:"1px solid #ff8c0035", display:"flex",
            alignItems:"center", justifyContent:"center", fontSize:"24px",
            boxShadow:"0 0 20px #ff8c0015" }}>🎯</div>
          <div>
            <h1 style={{ margin:0, fontSize:"26px", fontWeight:"800",
              letterSpacing:"-0.5px", fontFamily:"JetBrains Mono, monospace",
              background:"linear-gradient(135deg, #ff8c00, #ffd600)",
              WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent" }}>
              Identity Drift Detector
            </h1>
            <div style={{ fontSize:"13px", color:C.muted, marginTop:"2px" }}>
              IAM change detection · Privilege creep · Policy drift · Zero-Trust enforcement
            </div>
          </div>
        </div>
        <button onClick={handleScan} disabled={scanning}
          style={{ padding:"12px 28px", borderRadius:"12px", border:"none",
            cursor:scanning?"not-allowed":"pointer", fontSize:"14px",
            fontWeight:"800",
            background:scanning?C.surface
              :"linear-gradient(135deg, #ff8c00, #ffd600)",
            color:scanning?C.muted:"#000",
            boxShadow:scanning?"none":"0 0 24px rgba(255,140,0,0.3)",
            display:"flex", alignItems:"center", gap:"8px",
            transition:"all 0.2s" }}>
          {scanning?"Scanning...":"▶ Run Drift Scan"}
        </button>
      </div>

      {/* Stats */}
      {stats && (
        <div style={{ display:"grid", gridTemplateColumns:"repeat(5,1fr)",
          gap:"12px", marginBottom:"28px" }}>
          {[
            { label:"Identities",      value:stats.total_identities,        color:"#ff8c00", icon:"👤" },
            { label:"Open Drifts",     value:stats.total_drifts,            color:"#ff3b5c", icon:"⚡" },
            { label:"Critical",        value:stats.critical_drifts,         color:"#ff3b5c", icon:"🚨" },
            { label:"High Drift",      value:stats.high_drift_identities,   color:"#ff8c00", icon:"📈" },
            { label:"Avg Drift Score", value:`${stats.avg_drift_score}`,    color:stats.avg_drift_score>=50?"#ff3b5c":stats.avg_drift_score>=25?"#ffd600":"#00ff88", icon:"📊" },
          ].map(s => (
            <div key={s.label} style={{ ...cardStyle({ padding:"18px" }),
              borderColor:s.color+"25" }}>
              <div style={{ fontSize:"18px", marginBottom:"6px" }}>{s.icon}</div>
              <div style={{ fontSize:"22px", fontWeight:"800",
                fontFamily:"JetBrains Mono, monospace",
                color:s.color, lineHeight:1 }}>{s.value}</div>
              <div style={{ fontSize:"10px", color:C.muted, marginTop:"4px",
                textTransform:"uppercase", letterSpacing:"0.5px" }}>{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Tabs */}
      <div style={{ display:"flex", gap:"4px", marginBottom:"20px",
        background:C.card, padding:"4px", borderRadius:"12px",
        border:`1px solid ${C.border}`, width:"fit-content" }}>
        {[
          { id:"drifts",    label:`Drifts (${drifts.length})`       },
          { id:"baselines", label:`Identities (${baselines.length})` },
        ].map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            style={{ padding:"8px 18px", borderRadius:"9px", border:"none",
              cursor:"pointer", fontSize:"13px", fontWeight:"600",
              transition:"all 0.2s",
              background:tab===t.id
                ?"linear-gradient(135deg,#ff8c0020,#ffd60008)":"transparent",
              color:tab===t.id?C.text:C.muted,
              boxShadow:tab===t.id?"inset 0 0 0 1px #ff8c0030":"none" }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Drifts tab */}
      {tab === "drifts" && (
        <div>
          {/* Severity filter */}
          <div style={{ display:"flex", gap:"8px",
            marginBottom:"16px", flexWrap:"wrap" }}>
            {["","Critical","High","Medium","Low"].map(s => {
              const color = SEV_COLOR[s] || C.cyan;
              return (
                <button key={s} onClick={() => setSevFilter(s)}
                  style={{ padding:"5px 14px", borderRadius:"100px",
                    border:`1px solid ${sevFilter===s?color:C.border}`,
                    background:sevFilter===s?color+"20":"transparent",
                    color:sevFilter===s?color:C.muted,
                    cursor:"pointer", fontSize:"12px",
                    fontWeight:sevFilter===s?"700":"400" }}>
                  {s||"All Severities"}
                </button>
              );
            })}
          </div>

          <div style={{ display:"flex", flexDirection:"column", gap:"8px" }}>
            {drifts.length === 0 ? (
              <div style={{ ...cardStyle({ padding:"48px", textAlign:"center" }),
                color:C.muted }}>
                No open drifts detected. Run a scan to check for changes.
              </div>
            ) : drifts.map(drift => {
              const sc = SEV_COLOR[drift.severity] || "#64748b";
              const dm = DRIFT_META[drift.drift_type] ||
                { icon:"⚡", label:drift.drift_type, color:"#64748b" };
              const bl = baselines.find(b => b.id === drift.baseline_id);
              const pc = bl ? (PROVIDER_COLOR[bl.provider] || "#64748b") : "#64748b";
              return (
                <div key={drift.id} style={{ background:C.card,
                  border:`1px solid ${sc}20`,
                  borderLeft:`3px solid ${sc}`,
                  borderRadius:"12px", padding:"14px 16px" }}>
                  <div style={{ display:"flex",
                    alignItems:"flex-start", gap:"12px" }}>
                    <div style={{ fontSize:"20px", flexShrink:0,
                      marginTop:"2px" }}>{dm.icon}</div>
                    <div style={{ flex:1 }}>
                      {/* Badges */}
                      <div style={{ display:"flex", gap:"6px",
                        flexWrap:"wrap", marginBottom:"6px" }}>
                        <span style={{ padding:"2px 8px",
                          borderRadius:"100px", fontSize:"9px",
                          fontWeight:"800", background:sc+"15",
                          color:sc, textTransform:"uppercase" }}>
                          {drift.severity}
                        </span>
                        <span style={{ padding:"2px 8px",
                          borderRadius:"100px", fontSize:"10px",
                          background:dm.color+"15", color:dm.color }}>
                          {dm.label}
                        </span>
                        {bl && (
                          <span style={{ padding:"2px 8px",
                            borderRadius:"100px", fontSize:"10px",
                            background:pc+"15", color:pc }}>
                            {bl.provider.toUpperCase()}
                          </span>
                        )}
                        <span style={{ fontSize:"10px", color:C.faint,
                          marginLeft:"auto" }}>
                          {new Date(drift.detected_at).toLocaleDateString()}
                        </span>
                      </div>
                      {/* Title */}
                      <div style={{ fontWeight:"700", fontSize:"13px",
                        marginBottom:"4px" }}>{drift.title}</div>
                      {/* Description */}
                      <div style={{ fontSize:"11px", color:C.muted,
                        lineHeight:"1.5", marginBottom:"8px" }}>
                        {drift.description}
                      </div>
                      {/* Old vs New */}
                      {drift.old_value && (
                        <div style={{ display:"flex", gap:"12px",
                          marginBottom:"8px" }}>
                          <div style={{ flex:1, padding:"7px 10px",
                            borderRadius:"8px", background:"#00ff8808",
                            border:"1px solid #00ff8820" }}>
                            <div style={{ fontSize:"9px", color:"#00ff88",
                              fontWeight:"700", textTransform:"uppercase",
                              marginBottom:"3px" }}>Baseline</div>
                            <div style={{ fontSize:"10px", color:C.muted,
                              fontFamily:"JetBrains Mono, monospace",
                              overflow:"hidden", textOverflow:"ellipsis",
                              whiteSpace:"nowrap" }}>{drift.old_value}</div>
                          </div>
                          <div style={{ flex:1, padding:"7px 10px",
                            borderRadius:"8px", background:"#ff3b5c08",
                            border:"1px solid #ff3b5c20" }}>
                            <div style={{ fontSize:"9px", color:"#ff3b5c",
                              fontWeight:"700", textTransform:"uppercase",
                              marginBottom:"3px" }}>Current (Drifted)</div>
                            <div style={{ fontSize:"10px", color:C.muted,
                              fontFamily:"JetBrains Mono, monospace",
                              overflow:"hidden", textOverflow:"ellipsis",
                              whiteSpace:"nowrap" }}>{drift.new_value}</div>
                          </div>
                        </div>
                      )}
                      {/* Remediation */}
                      {drift.remediation && (
                        <div style={{ fontSize:"11px", color:"#00ff88",
                          padding:"6px 10px", borderRadius:"6px",
                          background:"#00ff8808",
                          border:"1px solid #00ff8820" }}>
                          🔧 {drift.remediation}
                        </div>
                      )}
                      {drift.regulation && (
                        <div style={{ fontSize:"10px", color:"#a78bfa",
                          marginTop:"5px" }}>📋 {drift.regulation}</div>
                      )}
                    </div>
                    {/* Actions */}
                    <div style={{ display:"flex", flexDirection:"column",
                      gap:"4px", flexShrink:0 }}>
                      <button onClick={() => handleUpdate(drift.id,"resolved")}
                        disabled={updating[drift.id]}
                        style={{ padding:"5px 10px", borderRadius:"7px",
                          border:"1px solid #00ff8830", cursor:"pointer",
                          fontSize:"11px", fontWeight:"600",
                          background:"#00ff8810", color:"#00ff88" }}>
                        Resolve
                      </button>
                      <button onClick={() => handleUpdate(drift.id,"accepted")}
                        disabled={updating[drift.id]}
                        style={{ padding:"5px 10px", borderRadius:"7px",
                          border:"1px solid #64748b30", cursor:"pointer",
                          fontSize:"11px", background:"transparent",
                          color:"#64748b" }}>
                        Accept
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Baselines tab */}
      {tab === "baselines" && (
        <div style={{ display:"grid",
          gridTemplateColumns:"repeat(2,1fr)", gap:"12px" }}>
          {baselines.map(b => {
            const dc  = DRIFT_COLOR(b.drift_score);
            const pc  = PROVIDER_COLOR[b.provider] || "#64748b";
            const isSel = selBaseline?.id === b.id;
            return (
              <div key={b.id}
                onClick={() => setSelBaseline(isSel ? null : b)}
                style={{ ...cardStyle({ cursor:"pointer",
                  borderColor:isSel ? dc+"50" : C.border }),
                  boxShadow:isSel ? `0 0 16px ${dc}10` : "none" }}>
                <div style={{ display:"flex", alignItems:"center",
                  gap:"12px" }}>
                  {/* Drift score gauge */}
                  <div style={{ width:"52px", height:"52px",
                    borderRadius:"50%", flexShrink:0,
                    background:dc+"12", border:`2px solid ${dc}`,
                    display:"flex", flexDirection:"column",
                    alignItems:"center", justifyContent:"center" }}>
                    <div style={{ fontSize:"15px", fontWeight:"900",
                      color:dc, fontFamily:"JetBrains Mono, monospace",
                      lineHeight:1 }}>{b.drift_score}</div>
                    <div style={{ fontSize:"7px", color:dc }}>DRIFT</div>
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:"700", fontSize:"13px",
                      marginBottom:"4px", overflow:"hidden",
                      textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                      {b.identity_name}
                    </div>
                    <div style={{ display:"flex", gap:"6px",
                      marginBottom:"6px" }}>
                      <span style={{ padding:"2px 7px",
                        borderRadius:"100px", fontSize:"10px",
                        background:pc+"15", color:pc }}>
                        {b.provider.toUpperCase()}
                      </span>
                      <span style={{ padding:"2px 7px",
                        borderRadius:"100px", fontSize:"10px",
                        background:C.surface, color:C.muted }}>
                        {b.identity_type}
                      </span>
                      <span style={{ fontSize:"10px", color:C.muted }}>
                        {b.permission_count} permissions
                      </span>
                    </div>
                    {/* Drift bar */}
                    <div style={{ height:"3px", background:C.faint,
                      borderRadius:"2px" }}>
                      <div style={{ height:"100%",
                        width:`${b.drift_score}%`,
                        background:dc, borderRadius:"2px",
                        transition:"width 0.5s ease" }} />
                    </div>
                  </div>
                  {b.drift_count > 0 && (
                    <div style={{ padding:"3px 8px",
                      borderRadius:"100px", fontSize:"10px",
                      fontWeight:"700", background:dc+"15",
                      color:dc, flexShrink:0 }}>
                      {b.drift_count} drifts
                    </div>
                  )}
                </div>
                {/* Reset baseline button */}
                {isSel && (
                  <div style={{ marginTop:"12px", display:"flex",
                    gap:"8px" }}>
                    <button onClick={(e) => {
                      e.stopPropagation();
                      handleReset(b.id);
                    }} style={{ flex:1, padding:"8px",
                      borderRadius:"8px",
                      border:"1px solid #00e5ff30",
                      cursor:"pointer", fontSize:"12px",
                      fontWeight:"600",
                      background:"#00e5ff10", color:"#00e5ff" }}>
                      ↺ Reset Baseline
                    </button>
                    <div style={{ flex:2, padding:"8px",
                      borderRadius:"8px", background:C.surface,
                      fontSize:"11px", color:C.muted }}>
                      Baseline set: {new Date(b.baseline_set_at).toLocaleDateString()}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

